/**
 * Official MySQL Error Message Reference catalog from the current docs.
 * Sources:
 * - server: https://dev.mysql.com/doc/mysql-errors/en/server-error-reference.html
 * - client: https://dev.mysql.com/doc/mysql-errors/en/client-error-reference.html
 * - global: https://dev.mysql.com/doc/mysql-errors/en/global-error-reference.html
 */

export const mysqlErrorCategories = {
  server: "server",
  client: "client",
  global: "global"
} as const

export type MysqlErrorCategory = keyof typeof mysqlErrorCategories
type MysqlErrorSymbolPattern = string
type MysqlErrorNumberPattern = `${number}` | `MY-${number}`

type StripMysqlPrefix<Symbol extends string> =
  Symbol extends `ER_${infer Rest}` ? Rest :
  Symbol extends `CR_${infer Rest}` ? Rest :
  Symbol extends `EE_${infer Rest}` ? Rest :
  Symbol

type KebabCase<S extends string> = S extends `${infer Head}_${infer Tail}`
  ? `${Lowercase<Head>}-${KebabCase<Tail>}`
  : Lowercase<S>

export type MysqlCategoryOfSymbol<Symbol extends string> =
  Symbol extends `ER_${string}` ? "server" :
  Symbol extends `CR_${string}` ? "client" :
  Symbol extends `EE_${string}` ? "global" :
  MysqlErrorCategory

type MysqlErrorTagFor<Symbol extends string> =
  `@mysql/${MysqlCategoryOfSymbol<Symbol>}/${KebabCase<StripMysqlPrefix<Symbol>>}`

interface MysqlErrorDescriptorShape<Symbol extends MysqlErrorSymbolPattern = MysqlErrorSymbolPattern> {
  readonly category: MysqlCategoryOfSymbol<Symbol>
  readonly number: MysqlErrorNumberPattern
  readonly symbol: Symbol
  readonly sqlState?: string
  readonly tag: MysqlErrorTagFor<Symbol>
  readonly messageTemplate: string
}

